  FILTER(CONTAINS(LCASE(STR(?label)), "company") || CONTAINS(LCASE(STR(?label)), "reliance") || CONTAINS(LCASE(STR(?label)), "cricket") || CONTAINS(LCASE(STR(?label)), "stadium") || CONTAINS(LCASE(STR(?label)), "fortune") || CONTAINS(LCASE(STR(?label)), "global") || CONTAINS(LCASE(STR(?label)), "list"))
}
